import{_ as a,o as e,c as n,O as t}from"./chunks/framework.bdcb0ee1.js";const g=JSON.parse('{"title":"Banning Users","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/banning.md","filePath":"administration/users/banning.md","lastUpdated":1773167148000}'),r={name:"administration/users/banning.md"},s=t('<h1 id="banning-users" tabindex="-1">Banning Users <a class="header-anchor" href="#banning-users" aria-label="Permalink to &quot;Banning Users&quot;">​</a></h1><p>Banning prevents a user from accessing your board. Bans can be permanent or temporary, and are managed from the user&#39;s profile in the Admin CP or through the moderation tools.</p><nav class="table-of-contents"><ul><li><a href="#ban-types">Ban types</a><ul><li><a href="#permanent-ban">Permanent ban</a></li><li><a href="#temporary-ban">Temporary ban</a></li></ul></li><li><a href="#creating-a-ban">Creating a ban</a></li><li><a href="#what-banned-users-see">What banned users see</a></li><li><a href="#managing-bans">Managing bans</a></li></ul></nav><h2 id="ban-types" tabindex="-1">Ban types <a class="header-anchor" href="#ban-types" aria-label="Permalink to &quot;Ban types&quot;">​</a></h2><h3 id="permanent-ban" tabindex="-1">Permanent ban <a class="header-anchor" href="#permanent-ban" aria-label="Permalink to &quot;Permanent ban&quot;">​</a></h3><p>A permanent ban has no expiry date. The user is blocked from accessing the board indefinitely, until an administrator manually lifts the ban.</p><h3 id="temporary-ban" tabindex="-1">Temporary ban <a class="header-anchor" href="#temporary-ban" aria-label="Permalink to &quot;Temporary ban&quot;">​</a></h3><p>A temporary ban expires after a set duration. You can specify the length using a number and a time unit:</p><ul><li><strong>Hours</strong> — e.g. 24 hours</li><li><strong>Days</strong> — e.g. 7 days</li><li><strong>Weeks</strong> — e.g. 2 weeks</li></ul><p>Once the ban expires, the user regains access to the board automatically.</p><h2 id="creating-a-ban" tabindex="-1">Creating a ban <a class="header-anchor" href="#creating-a-ban" aria-label="Permalink to &quot;Creating a ban&quot;">​</a></h2><p>When banning a user, you will be asked to provide:</p><ul><li><strong>Reason</strong> — a short explanation for the ban (up to 255 characters). This is visible to the banned user when they attempt to access the board.</li><li><strong>Duration</strong> — choose <strong>permanent</strong> or set a time period using the interval and type fields.</li></ul><img width="1949" height="745" alt="image" src="https://github.com/user-attachments/assets/8e898892-a48c-4f4e-bb80-f14fbb9b59f4"><h2 id="what-banned-users-see" tabindex="-1">What banned users see <a class="header-anchor" href="#what-banned-users-see" aria-label="Permalink to &quot;What banned users see&quot;">​</a></h2><p>When a banned user tries to access any page on the board, they are shown a dedicated ban notice page displaying:</p><ul><li>The reason for their ban.</li><li>For temporary bans, when the ban expires.</li></ul><p>Banned users cannot access any board features. The only action available to them is logging out.</p><h2 id="managing-bans" tabindex="-1">Managing bans <a class="header-anchor" href="#managing-bans" aria-label="Permalink to &quot;Managing bans&quot;">​</a></h2><p>The ban list in the Admin CP shows all currently active bans. Expired temporary bans are automatically removed from the list.</p><p>To lift a ban early, delete it from the user&#39;s ban list. The user will immediately regain access to the board.</p><blockquote><p>Note: Banning is account-based. There is no IP-based banning — if a banned user creates a new account, they will be able to access the board unless that account is also banned.</p></blockquote>',22),i=[s];function o(l,h,b,d,c,u){return e(),n("div",null,i)}const m=a(r,[["render",o]]);export{g as __pageData,m as default};
